/**
 * Phase 12B: Transformers.js Benchmark Suite
 *
 * Self-contained benchmark comparing v3.8.1 vs v4.0.0-next.9 performance
 * across CLIP, Depth, and Florence-2 pipelines. Imports libraries directly
 * from CDN — no manual CDN swapping needed.
 *
 * ⚠️ This file is large (~1-3MB) due to embedded test images. Dev-only.
 *
 * Prerequisites:
 *   - All three models must be cached (CLIP, Depth, Florence-2)
 *   - Use Model Manager to download if needed
 *   - Close other tabs to avoid memory pressure
 *
 * Usage:
 *   // Run all three configurations (v3, v4, v4-wasm) — ~30-45 minutes
 *   ImageDescriberBenchmark.runAll()
 *
 *   // Run a single configuration
 *   ImageDescriberBenchmark.run("v4", { cdnUrl: "https://cdn.jsdelivr.net/npm/@huggingface/transformers@4.0.0-next.9" })
 *
 *   // Compare stored results
 *   ImageDescriberBenchmark.compare()
 *
 *   // List stored results
 *   ImageDescriberBenchmark.listResults()
 *
 *   // Clear all stored benchmark data
 *   ImageDescriberBenchmark.clearResults()
 *
 *   // Get raw data for one configuration
 *   ImageDescriberBenchmark.getResults("v4")
 */

const BENCHMARK_IMAGES = [
  { key: "bacteria_agar", name: "Bacteria on agar plate", dataUrl: "data:image/jpeg;base64," },
  { key: "tsunami", name: "Indian Ocean Tsunami", dataUrl: "data:image/jpeg;base64," },
  { key: "piston", name: "Piston diagram", dataUrl: "data:image/jpeg;base64," },
  { key: "probability", name: "Probability of exceedance", dataUrl: "data:image/jpeg;base64," },
  { key: "mechanism_ga", name: "Mechanism of action (GA)", dataUrl: "data:image/jpeg;base64," },
  { key: "pv", name: "PV diagram", dataUrl: "data:image/jpeg;base64," },
  { key: "siege_rouen", name: "Siège de Rouen", dataUrl: "data:image/jpeg;base64," },
];


window.ImageDescriberBenchmark = (function () {
  'use strict';

  // ───────────────────────────────────────────────────────
  // Logging configuration
  // ───────────────────────────────────────────────────────
  const LOG_LEVELS = { ERROR: 0, WARN: 1, INFO: 2, DEBUG: 3 };
  const DEFAULT_LOG_LEVEL = LOG_LEVELS.INFO;
  const ENABLE_ALL_LOGGING = false;
  const DISABLE_ALL_LOGGING = false;

  function shouldLog(level) {
    if (DISABLE_ALL_LOGGING) return false;
    if (ENABLE_ALL_LOGGING) return true;
    return level <= DEFAULT_LOG_LEVEL;
  }

  function logError(message) {
    var args = Array.prototype.slice.call(arguments);
    if (shouldLog(LOG_LEVELS.ERROR)) console.error.apply(console, args);
  }

  function logWarn(message) {
    var args = Array.prototype.slice.call(arguments);
    if (shouldLog(LOG_LEVELS.WARN)) console.warn.apply(console, args);
  }

  function logInfo(message) {
    var args = Array.prototype.slice.call(arguments);
    if (shouldLog(LOG_LEVELS.INFO)) console.log.apply(console, args);
  }

  function logDebug(message) {
    var args = Array.prototype.slice.call(arguments);
    if (shouldLog(LOG_LEVELS.DEBUG)) console.log.apply(console, args);
  }

  // ───────────────────────────────────────────────────────
  // Constants
  // ───────────────────────────────────────────────────────
  const CDN_V3 = "https://cdn.jsdelivr.net/npm/@huggingface/transformers@3.8.1";
  const CDN_V4 = "https://cdn.jsdelivr.net/npm/@huggingface/transformers@4.0.0-next.9";

  const STORAGE_PREFIX = "imgdesc-benchmark-";

  const CLIP_LABELS = [
    "photograph", "chart", "diagram", "illustration", "screenshot",
    "map", "table", "equation", "graph", "flowchart"
  ];

  const CLIP_MODEL = "Xenova/clip-vit-base-patch32";
  const DEPTH_MODEL = "onnx-community/depth-anything-v2-small";
  const FLORENCE_MODEL = "onnx-community/Florence-2-base-ft";

  const FLORENCE_TIMEOUT_MS = 2 * 60 * 1000; // 2 minutes

  // ───────────────────────────────────────────────────────
  // Utility helpers
  // ───────────────────────────────────────────────────────

  function formatMs(ms) {
    return ms.toLocaleString('en-GB', { maximumFractionDigits: 0 });
  }

  function formatElapsed(startMs) {
    const elapsed = (performance.now() - startMs) / 1000;
    const minutes = Math.floor(elapsed / 60);
    const seconds = Math.floor(elapsed % 60);
    return minutes + 'm ' + seconds + 's';
  }

  function median(arr) {
    if (arr.length === 0) return 0;
    const sorted = arr.slice().sort(function (a, b) { return a - b; });
    const mid = Math.floor(sorted.length / 2);
    return sorted.length % 2 !== 0 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
  }

  function mean(arr) {
    if (arr.length === 0) return 0;
    return arr.reduce(function (sum, v) { return sum + v; }, 0) / arr.length;
  }

  function padRight(str, len) {
    str = String(str);
    while (str.length < len) str += ' ';
    return str;
  }

  function padLeft(str, len) {
    str = String(str);
    while (str.length < len) str = ' ' + str;
    return str;
  }

  /**
   * Convert a data URL to an HTMLImageElement (for CLIP pipeline input).
   */
  function dataUrlToImage(dataUrl) {
    return new Promise(function (resolve, reject) {
      const img = new Image();
      img.onload = function () { resolve(img); };
      img.onerror = function (e) { reject(new Error('Failed to load image: ' + e)); };
      img.src = dataUrl;
    });
  }

  /**
   * Convert a data URL to a canvas element.
   */
  function dataUrlToCanvas(dataUrl) {
    return dataUrlToImage(dataUrl).then(function (img) {
      const canvas = document.createElement('canvas');
      canvas.width = img.naturalWidth;
      canvas.height = img.naturalHeight;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0);
      return canvas;
    });
  }

  /**
   * Detect WebGPU availability.
   */
  function isWebGPUAvailable() {
    return typeof navigator !== 'undefined' && !!navigator.gpu;
  }

  // ───────────────────────────────────────────────────────
  // Library import
  // ───────────────────────────────────────────────────────

  async function importLibrary(cdnUrl) {
    const t0 = performance.now();
    const module = await import(cdnUrl);
    const loadTime = performance.now() - t0;
    return { module: module, loadTime: loadTime };
  }

  /**
   * Try to detect the library version from the module.
   */
  function detectVersion(module) {
    if (module.env && module.env.version) return module.env.version;
    if (module.version) return module.version;
    if (module.env && module.env.__version) return module.env.__version;
    return 'unknown';
  }

  /**
   * Attempt to force WASM backend in v4.
   */
  function forceWasmBackend(module) {
    const notes = [];
    if (module.env) {
      if ('device' in module.env) {
        module.env.device = 'wasm';
        notes.push('Set env.device = "wasm"');
      }
      if (module.env.backends && module.env.backends.onnx) {
        notes.push('env.backends.onnx keys: ' + JSON.stringify(Object.keys(module.env.backends.onnx)));
      }
    }
    if (notes.length === 0) {
      notes.push('Could not find env.device — WASM forcing may not have taken effect');
    }
    return notes;
  }

  // ───────────────────────────────────────────────────────
  // Pipeline benchmarks
  // ───────────────────────────────────────────────────────

  /**
   * Benchmark CLIP zero-shot classification.
   */
  async function benchmarkClip(module, images) {
    logInfo('');
    logInfo('── CLIP Classification ──');

    const t0 = performance.now();
    let clipPipeline;
    try {
      clipPipeline = await module.pipeline('zero-shot-image-classification', CLIP_MODEL);
    } catch (e) {
      logError('Failed to create CLIP pipeline:', e.message);
      return { error: e.message };
    }
    const pipelineCreateMs = performance.now() - t0;
    logInfo('Pipeline created in ' + formatMs(pipelineCreateMs) + 'ms');

    const runs = [];
    for (let i = 0; i < images.length; i++) {
      const img = images[i];
      const cold = (i === 0);
      const prefix = cold ? '  \u2744 ' : '  \uD83D\uDD25 ';

      try {
        const runT0 = performance.now();
        const result = await clipPipeline(img.dataUrl, CLIP_LABELS);
        const ms = performance.now() - runT0;

        const topLabel = result[0] ? result[0].label : 'none';
        const confidence = result[0] ? result[0].score : 0;
        const confPct = Math.round(confidence * 100);

        runs.push({
          key: img.key,
          ms: Math.round(ms),
          cold: cold,
          topLabel: topLabel,
          confidence: Math.round(confidence * 1000) / 1000
        });

        logInfo(prefix + padRight(img.key, 20) + padLeft(formatMs(ms), 8) + 'ms  \u2192 ' + topLabel + ' (' + confPct + '%)');
      } catch (e) {
        logError('  CLIP error on ' + img.key + ':', e.message);
        runs.push({ key: img.key, ms: 0, cold: cold, error: e.message });
      }
    }

    // Compute warm stats
    const warmMs = runs.filter(function (r) { return !r.cold && !r.error; }).map(function (r) { return r.ms; });
    const warmMedianMs = Math.round(median(warmMs));
    const warmMeanMs = Math.round(mean(warmMs));
    logInfo('  Warm: median ' + formatMs(warmMedianMs) + 'ms | mean ' + formatMs(warmMeanMs) + 'ms');

    // Dispose
    if (clipPipeline && typeof clipPipeline.dispose === 'function') {
      try { await clipPipeline.dispose(); } catch (e) { logDebug('CLIP dispose error:', e.message); }
    }

    return {
      pipelineCreateMs: Math.round(pipelineCreateMs),
      runs: runs,
      warmMedianMs: warmMedianMs,
      warmMeanMs: warmMeanMs
    };
  }

  /**
   * Benchmark Depth Anything V2.
   */
  async function benchmarkDepth(module, images) {
    logInfo('');
    logInfo('── Depth Estimation ──');

    const t0 = performance.now();
    let depthPipeline;
    try {
      depthPipeline = await module.pipeline('depth-estimation', DEPTH_MODEL);
    } catch (e) {
      logError('Failed to create Depth pipeline:', e.message);
      return { error: e.message };
    }
    const pipelineCreateMs = performance.now() - t0;
    logInfo('Pipeline created in ' + formatMs(pipelineCreateMs) + 'ms');

    const runs = [];
    for (let i = 0; i < images.length; i++) {
      const img = images[i];
      const cold = (i === 0);
      const prefix = cold ? '  \u2744 ' : '  \uD83D\uDD25 ';

      try {
        const runT0 = performance.now();
        await depthPipeline(img.dataUrl);
        const ms = performance.now() - runT0;

        runs.push({
          key: img.key,
          ms: Math.round(ms),
          cold: cold
        });

        logInfo(prefix + padRight(img.key, 20) + padLeft(formatMs(ms), 8) + 'ms');
      } catch (e) {
        logError('  Depth error on ' + img.key + ':', e.message);
        runs.push({ key: img.key, ms: 0, cold: cold, error: e.message });
      }
    }

    // Compute warm stats
    const warmMs = runs.filter(function (r) { return !r.cold && !r.error; }).map(function (r) { return r.ms; });
    const warmMedianMs = Math.round(median(warmMs));
    const warmMeanMs = Math.round(mean(warmMs));
    logInfo('  Warm: median ' + formatMs(warmMedianMs) + 'ms | mean ' + formatMs(warmMeanMs) + 'ms');

    // Dispose
    if (depthPipeline && typeof depthPipeline.dispose === 'function') {
      try { await depthPipeline.dispose(); } catch (e) { logDebug('Depth dispose error:', e.message); }
    }

    return {
      pipelineCreateMs: Math.round(pipelineCreateMs),
      runs: runs,
      warmMedianMs: warmMedianMs,
      warmMeanMs: warmMeanMs
    };
  }

  /**
   * Benchmark Florence-2 captioning.
   */
  async function benchmarkFlorence(module, images) {
    logInfo('');
    logInfo('── Florence-2 Caption ──');

    const taskToken = '<CAPTION>';
    let model, processor, tokenizer;
    const t0 = performance.now();

    try {
      // Race against timeout
      const loadPromise = Promise.all([
        module.Florence2ForConditionalGeneration.from_pretrained(FLORENCE_MODEL, { dtype: 'fp32' }),
        module.AutoProcessor.from_pretrained(FLORENCE_MODEL),
        module.AutoTokenizer.from_pretrained(FLORENCE_MODEL)
      ]);

      const timeoutPromise = new Promise(function (_, reject) {
        setTimeout(function () {
          reject(new Error('Florence-2 model load timed out after 2 minutes'));
        }, FLORENCE_TIMEOUT_MS);
      });

      const components = await Promise.race([loadPromise, timeoutPromise]);
      model = components[0];
      processor = components[1];
      tokenizer = components[2];
    } catch (e) {
      logWarn('Florence-2 models not cached or load failed — skipping. Download via Model Manager first.');
      logWarn('Error: ' + e.message);
      return { error: e.message, skipped: true };
    }

    const componentLoadMs = performance.now() - t0;
    logInfo('Components loaded in ' + formatMs(componentLoadMs) + 'ms');

    const runs = [];
    for (let i = 0; i < images.length; i++) {
      const img = images[i];
      const cold = (i === 0);
      const prefix = cold ? '  \u2744 ' : '  \uD83D\uDD25 ';

      try {
        const runT0 = performance.now();

        // Read image
        const rawImage = await module.RawImage.read(img.dataUrl);

        // Build inputs — try construct_prompts first, fallback to direct tokenisation
        let textInputs;
        if (processor.construct_prompts && typeof processor.construct_prompts === 'function') {
          const prompts = processor.construct_prompts(taskToken);
          textInputs = tokenizer(prompts);
        } else {
          logDebug('construct_prompts not found, using direct tokenisation');
          textInputs = tokenizer(taskToken);
        }

        const visionInputs = await processor(rawImage);

        // Generate
        const generatedIds = await model.generate(
          Object.assign({}, textInputs, visionInputs, {
            max_new_tokens: 256,
            num_beams: 1,
            do_sample: false
          })
        );

        // Decode
        const generatedText = tokenizer.batch_decode(generatedIds, {
          skip_special_tokens: false
        })[0];

        // Post-process
        const result = processor.post_process_generation(
          generatedText,
          taskToken,
          rawImage.size
        );

        const captionText = result[taskToken] || generatedText;
        const ms = performance.now() - runT0;
        const captionLength = captionText.length;

        runs.push({
          key: img.key,
          ms: Math.round(ms),
          cold: cold,
          captionLength: captionLength
        });

        logInfo(prefix + padRight(img.key, 20) + padLeft(formatMs(ms), 8) + 'ms  (' + captionLength + ' chars)');
      } catch (e) {
        logError('  Florence error on ' + img.key + ':', e.message);
        runs.push({ key: img.key, ms: 0, cold: cold, error: e.message });
      }
    }

    // Compute warm stats
    const warmMs = runs.filter(function (r) { return !r.cold && !r.error; }).map(function (r) { return r.ms; });
    const warmMedianMs = Math.round(median(warmMs));
    const warmMeanMs = Math.round(mean(warmMs));
    logInfo('  Warm: median ' + formatMs(warmMedianMs) + 'ms | mean ' + formatMs(warmMeanMs) + 'ms');

    // Dispose model
    if (model && typeof model.dispose === 'function') {
      try { await model.dispose(); } catch (e) { logDebug('Florence dispose error:', e.message); }
    }

    return {
      componentLoadMs: Math.round(componentLoadMs),
      runs: runs,
      warmMedianMs: warmMedianMs,
      warmMeanMs: warmMeanMs
    };
  }

  // ───────────────────────────────────────────────────────
  // Storage helpers
  // ───────────────────────────────────────────────────────

  function saveResults(label, data) {
    try {
      localStorage.setItem(STORAGE_PREFIX + label, JSON.stringify(data));
      logInfo('Results saved as "' + label + '" \u2713');
    } catch (e) {
      logError('Failed to save results:', e.message);
    }
  }

  function loadResults(label) {
    try {
      const raw = localStorage.getItem(STORAGE_PREFIX + label);
      return raw ? JSON.parse(raw) : null;
    } catch (e) {
      logError('Failed to load results for "' + label + '":', e.message);
      return null;
    }
  }

  function getAllResultLabels() {
    const labels = [];
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.indexOf(STORAGE_PREFIX) === 0) {
        labels.push(key.substring(STORAGE_PREFIX.length));
      }
    }
    return labels.sort();
  }

  // ───────────────────────────────────────────────────────
  // Main run function
  // ───────────────────────────────────────────────────────

  async function run(label, options) {
    options = options || {};
    const cdnUrl = options.cdnUrl;
    if (!cdnUrl) {
      logError('run() requires options.cdnUrl');
      return;
    }

    const forceWasm = !!options.forceWasm;
    const pipelinesToRun = options.pipelines || ['clip', 'depth', 'florence'];
    const imageKeys = options.images || null;

    // Filter images
    let images = BENCHMARK_IMAGES;
    if (imageKeys) {
      images = BENCHMARK_IMAGES.filter(function (img) {
        return imageKeys.indexOf(img.key) !== -1;
      });
    }

    if (images.length === 0) {
      logError('No images found for benchmark');
      return;
    }

    const configStartTime = performance.now();

    logInfo('');
    logInfo('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
    logInfo(' Image Describer Benchmark: "' + label + '"');
    logInfo('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');

    // Import library
    let lib;
    try {
      lib = await importLibrary(cdnUrl);
    } catch (e) {
      logError('Failed to import library from ' + cdnUrl + ':', e.message);
      return;
    }

    const module = lib.module;
    const libraryLoadMs = Math.round(lib.loadTime);
    const libraryVersion = detectVersion(module);
    const webgpuAvailable = isWebGPUAvailable();

    logInfo('Library: v' + libraryVersion + ' loaded in ' + formatMs(libraryLoadMs) + 'ms');

    let deviceUsed = 'unknown';
    let wasmNotes = [];
    if (forceWasm) {
      wasmNotes = forceWasmBackend(module);
      deviceUsed = 'wasm';
      logInfo('Device: WASM forced');
      wasmNotes.forEach(function (note) { logInfo('  ' + note); });
    } else {
      deviceUsed = webgpuAvailable ? 'webgpu (auto)' : 'wasm (auto)';
      logInfo('Device: ' + deviceUsed);
    }
    logInfo('WebGPU: ' + (webgpuAvailable ? '\u2713 supported' : '\u2717 not available'));

    // Build result structure
    const result = {
      label: label,
      timestamp: new Date().toISOString(),
      userAgent: navigator.userAgent,
      webgpuAvailable: webgpuAvailable,
      deviceUsed: deviceUsed,
      libraryLoadMs: libraryLoadMs,
      libraryVersion: libraryVersion,
      wasmNotes: wasmNotes
    };

    // Run selected pipelines
    if (pipelinesToRun.indexOf('clip') !== -1) {
      try {
        result.clip = await benchmarkClip(module, images);
      } catch (e) {
        logError('CLIP benchmark failed:', e.message);
        result.clip = { error: e.message };
      }
    }

    if (pipelinesToRun.indexOf('depth') !== -1) {
      try {
        result.depth = await benchmarkDepth(module, images);
      } catch (e) {
        logError('Depth benchmark failed:', e.message);
        result.depth = { error: e.message };
      }
    }

    if (pipelinesToRun.indexOf('florence') !== -1) {
      try {
        result.florence = await benchmarkFlorence(module, images);
      } catch (e) {
        logError('Florence benchmark failed:', e.message);
        result.florence = { error: e.message };
      }
    }

    // Save
    saveResults(label, result);

    logInfo('');
    logInfo('\u2500\u2500 Configuration "' + label + '" complete (' + formatElapsed(configStartTime) + ') \u2500\u2500');

    return result;
  }

  // ───────────────────────────────────────────────────────
  // runAll
  // ───────────────────────────────────────────────────────

  async function runAll() {
    logInfo('Starting full benchmark suite \u2014 this will take 30\u201345 minutes');
    logInfo('You can leave this running unattended');
    logInfo('');

    const suiteStart = performance.now();

    // 1. v3 benchmarks
    await run('v3', { cdnUrl: CDN_V3 });

    logInfo('');
    logInfo('\u2500\u2500 Starting configuration "v4" \u2500\u2500');

    // 2. v4 benchmarks (auto device)
    await run('v4', { cdnUrl: CDN_V4, forceWasm: false });

    logInfo('');
    logInfo('\u2500\u2500 Starting configuration "v4-wasm" \u2500\u2500');

    // 3. v4 with forced WASM
    await run('v4-wasm', { cdnUrl: CDN_V4, forceWasm: true });

    logInfo('');
    logInfo('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
    logInfo(' Full benchmark suite complete (' + formatElapsed(suiteStart) + ')');
    logInfo('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
    logInfo('');

    // Print comparison
    compare();
  }

  // ───────────────────────────────────────────────────────
  // compare
  // ───────────────────────────────────────────────────────

  function compare() {
    const labels = getAllResultLabels();
    if (labels.length === 0) {
      logInfo('No benchmark results found. Run ImageDescriberBenchmark.runAll() first.');
      return;
    }

    const datasets = {};
    labels.forEach(function (label) {
      datasets[label] = loadResults(label);
    });

    // Preferred order
    const orderedLabels = ['v3', 'v4', 'v4-wasm'].filter(function (l) {
      return labels.indexOf(l) !== -1;
    });
    // Add any labels not in the preferred list
    labels.forEach(function (l) {
      if (orderedLabels.indexOf(l) === -1) orderedLabels.push(l);
    });

    const hasV3 = !!datasets['v3'];
    const hasV4 = !!datasets['v4'];
    const showDelta = hasV3 && hasV4;

    logInfo('');
    logInfo('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
    logInfo(' Benchmark Comparison');
    logInfo('\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
    logInfo('Configurations: ' + orderedLabels.join(', '));

    // Print pipeline comparison tables
    var pipelineNames = [
      { key: 'clip', title: 'CLIP Classification' },
      { key: 'depth', title: 'Depth Estimation' },
      { key: 'florence', title: 'Florence-2 Caption' }
    ];

    pipelineNames.forEach(function (pDef) {
      logInfo('');
      logInfo('\u2500\u2500 ' + pDef.title + ' (warm runs, ms) \u2500\u2500');

      // Collect all image keys from any available result
      const allKeys = [];
      orderedLabels.forEach(function (label) {
        const d = datasets[label];
        if (d && d[pDef.key] && d[pDef.key].runs) {
          d[pDef.key].runs.forEach(function (r) {
            if (allKeys.indexOf(r.key) === -1 && !r.cold) allKeys.push(r.key);
          });
        }
      });

      if (allKeys.length === 0) {
        logInfo('  No data available');
        return;
      }

      // Build header
      const colWidth = 9;
      let header = padRight('Image', 20) + ' \u2502';
      orderedLabels.forEach(function (l) {
        header += padLeft(l, colWidth) + ' \u2502';
      });
      if (showDelta) header += padLeft('v4 vs v3', colWidth) + ' \u2502';
      logInfo(header);

      // Separator
      let sep = '';
      for (let i = 0; i < 20; i++) sep += '\u2500';
      sep += '\u253C';
      orderedLabels.forEach(function () {
        for (let i = 0; i < colWidth; i++) sep += '\u2500';
        sep += '\u2500\u253C';
      });
      if (showDelta) {
        for (let i = 0; i < colWidth; i++) sep += '\u2500';
        sep += '\u2500\u253C';
      }
      logInfo(sep);

      // Image rows (warm only)
      allKeys.forEach(function (imgKey) {
        let row = padRight(imgKey, 20) + ' \u2502';
        let v3Val = null, v4Val = null;

        orderedLabels.forEach(function (label) {
          const d = datasets[label];
          let val = '-';
          if (d && d[pDef.key] && d[pDef.key].runs) {
            const match = d[pDef.key].runs.filter(function (r) {
              return r.key === imgKey && !r.cold && !r.error;
            });
            if (match.length > 0) {
              val = formatMs(match[0].ms);
              if (label === 'v3') v3Val = match[0].ms;
              if (label === 'v4') v4Val = match[0].ms;
            }
          }
          row += padLeft(val, colWidth) + ' \u2502';
        });

        if (showDelta) {
          let delta = '-';
          if (v3Val !== null && v4Val !== null && v3Val > 0) {
            const pct = Math.round(((v4Val - v3Val) / v3Val) * 100);
            delta = (pct >= 0 ? '+' : '') + pct + '%';
          }
          row += padLeft(delta, colWidth) + ' \u2502';
        }

        logInfo(row);
      });

      // Separator
      logInfo(sep);

      // Summary rows
      var summaryRows = [
        { label: 'Cold start', getter: function (d) {
          if (!d || !d[pDef.key] || !d[pDef.key].runs) return null;
          var cold = d[pDef.key].runs.filter(function (r) { return r.cold && !r.error; });
          return cold.length > 0 ? cold[0].ms : null;
        }},
        { label: 'Warm median', getter: function (d) {
          return (d && d[pDef.key] && d[pDef.key].warmMedianMs != null) ? d[pDef.key].warmMedianMs : null;
        }},
        { label: 'Warm mean', getter: function (d) {
          return (d && d[pDef.key] && d[pDef.key].warmMeanMs != null) ? d[pDef.key].warmMeanMs : null;
        }},
        { label: 'Pipeline create', getter: function (d) {
          if (!d || !d[pDef.key]) return null;
          return d[pDef.key].pipelineCreateMs || d[pDef.key].componentLoadMs || null;
        }}
      ];

      summaryRows.forEach(function (sr) {
        let row = padRight(sr.label, 20) + ' \u2502';
        let v3Val = null, v4Val = null;

        orderedLabels.forEach(function (label) {
          const val = sr.getter(datasets[label]);
          if (label === 'v3') v3Val = val;
          if (label === 'v4') v4Val = val;
          row += padLeft(val !== null ? formatMs(val) : '-', colWidth) + ' \u2502';
        });

        if (showDelta) {
          let delta = '-';
          if (v3Val !== null && v4Val !== null && v3Val > 0) {
            const pct = Math.round(((v4Val - v3Val) / v3Val) * 100);
            delta = (pct >= 0 ? '+' : '') + pct + '%';
          }
          row += padLeft(delta, colWidth) + ' \u2502';
        }

        logInfo(row);
      });
    });

    // Summary section
    logInfo('');
    logInfo('\u2500\u2500 Summary \u2500\u2500');

    const colWidth = 9;
    let sHeader = padRight('', 20) + ' \u2502';
    orderedLabels.forEach(function (l) {
      sHeader += padLeft(l, colWidth) + ' \u2502';
    });
    if (showDelta) sHeader += padLeft('v4 vs v3', colWidth) + ' \u2502';
    logInfo(sHeader);

    // Library load
    let libRow = padRight('Library load', 20) + ' \u2502';
    let libV3 = null, libV4 = null;
    orderedLabels.forEach(function (label) {
      const d = datasets[label];
      const val = d ? d.libraryLoadMs : null;
      if (label === 'v3') libV3 = val;
      if (label === 'v4') libV4 = val;
      libRow += padLeft(val !== null ? formatMs(val) : '-', colWidth) + ' \u2502';
    });
    if (showDelta) {
      let delta = '-';
      if (libV3 !== null && libV4 !== null && libV3 > 0) {
        const pct = Math.round(((libV4 - libV3) / libV3) * 100);
        delta = (pct >= 0 ? '+' : '') + pct + '%';
      }
      libRow += padLeft(delta, colWidth) + ' \u2502';
    }
    logInfo(libRow);

    // WebGPU device
    let gpuRow = padRight('WebGPU device', 20) + ' \u2502';
    orderedLabels.forEach(function (label) {
      const d = datasets[label];
      let val = '-';
      if (d) {
        val = d.deviceUsed || (d.webgpuAvailable ? 'Yes' : 'No');
      }
      gpuRow += padLeft(val, colWidth) + ' \u2502';
    });
    if (showDelta) gpuRow += padLeft('', colWidth) + ' \u2502';
    logInfo(gpuRow);

    // Florence-2 model load
    let floRow = padRight('Flo-2 model load', 20) + ' \u2502';
    let floV3 = null, floV4 = null;
    orderedLabels.forEach(function (label) {
      const d = datasets[label];
      let val = null;
      if (d && d.florence && d.florence.componentLoadMs) {
        val = d.florence.componentLoadMs;
      }
      if (label === 'v3') floV3 = val;
      if (label === 'v4') floV4 = val;
      floRow += padLeft(val !== null ? formatMs(val) : '-', colWidth) + ' \u2502';
    });
    if (showDelta) {
      let delta = '-';
      if (floV3 !== null && floV4 !== null && floV3 > 0) {
        const pct = Math.round(((floV4 - floV3) / floV3) * 100);
        delta = (pct >= 0 ? '+' : '') + pct + '%';
      }
      floRow += padLeft(delta, colWidth) + ' \u2502';
    }
    logInfo(floRow);
  }

  // ───────────────────────────────────────────────────────
  // Utility API methods
  // ───────────────────────────────────────────────────────

  function clearResults() {
    const labels = getAllResultLabels();
    labels.forEach(function (label) {
      localStorage.removeItem(STORAGE_PREFIX + label);
    });
    logInfo('Cleared ' + labels.length + ' benchmark result(s)');
  }

  function getResults(label) {
    return loadResults(label);
  }

  function listResults() {
    const labels = getAllResultLabels();
    if (labels.length === 0) {
      logInfo('No benchmark results stored');
      return [];
    }

    logInfo('Stored benchmark results:');
    labels.forEach(function (label) {
      const data = loadResults(label);
      const ts = data ? data.timestamp : 'unknown';
      const device = data ? (data.deviceUsed || 'unknown') : 'unknown';
      logInfo('  \u2022 "' + label + '" — ' + ts + ' — device: ' + device);
    });
    return labels;
  }

  // ───────────────────────────────────────────────────────
  // Public API
  // ───────────────────────────────────────────────────────

  logDebug('Phase 12B: Benchmark suite loaded');

  return {
    runAll: runAll,
    run: run,
    compare: compare,
    clearResults: clearResults,
    getResults: getResults,
    listResults: listResults
  };

})();
